  return (
    <div className="App">
      <input onChange={(e) => setQuery(e.target.value.toLowerCase())} />
      {fruits.filter(f => f.toLowerCase().includes(query)).map(f => <p key={f}>{f}</p>)}
    </div>
  );
}

